mapper.sql:
where 1=1
and time_window_days=#{s.days}
and status=#{s.status}
and alert_level=#{s.alertLevel}

    and (
        alert_no like concat('%',#{s.keyword},'%')
        or product_name like concat('%',#{s.keyword},'%')
        or issue_keyword like concat('%',#{s.keyword},'%')
        or sample_reasons like concat('%',#{s.keyword},'%')
        or suggested_action like concat('%',#{s.keyword},'%')
    )

mapper.select:
select *
from product_issue_alert
where product_name=#{productName}
  and issue_keyword=#{issueKeyword}
  and time_window_days=#{timeWindowDays}
  and status='OPEN'
limit 1

select *
from product_issue_alert
where product_name=#{productName}
  and time_window_days=#{days}
  and status='OPEN'
order by trend_score desc, updated_at desc, id desc

select *
from product_issue_alert
where time_window_days=#{days}
  and status=#{status}
order by trend_score desc, issue_count desc, updated_at desc, id desc
limit 1

select count(*)
from product_issue_alert
where time_window_days=#{days}
  and status=#{status}
  and alert_level=#{alertLevel}

select count(distinct product_name)
from product_issue_alert
where time_window_days=#{days}
  and status=#{status}

select coalesce(sum(application_count), 0)
from product_issue_alert
where time_window_days=#{days}
  and status=#{status}
